-impl CapabilityAction {
-    const ALL: [Self; 4] = [
-        Self::AllowOnce,
-        Self::AllowAlways,
-        Self::Deny,
-        Self::DenyAlways,
-    ];
-
-    const fn label(self) -> &'static str {
-        match self {
-            Self::AllowOnce => "Allow Once",
-            Self::AllowAlways => "Allow Always",
-            Self::Deny => "Deny",
-            Self::DenyAlways => "Deny Always",
